function inferTags(name:string,pos:Pos,attrs:number[]){const tags:string[]=[];if(attrs[0]>=90)tags.push("PACE ABUSER");if(attrs[1]>=90)tags.push(pos==="ATT"?"POACHER":"GOAL THREAT");if(attrs[2]>=90)tags.push("CREATIVE PASSER");if(attrs[3]>=94)tags.push("PRESS RESISTANT");if(attrs[4]>=90)tags.push(pos==="GK"?"SHOT STOPPER":"DEFENSIVE WALL");if(attrs[5]>=92)tags.push("PHYSICAL FORCE");if(name==="Lionel Messi"||name==="Cristiano Ronaldo")tags.unshift("ERA PROOF");return tags.slice(0,3)}
