  {game==="player"&&picks.length===0&&!result&&<div className="setup"><span>YOUR POSITION</span>{(["ATT","MID","DEF","GK"] as Pos[]).map(p=><button className={position===p?"active":""} onClick={()=>{setPosition(p);resetForChoice()}} key={p}>{p}</button>)}</div>}
  {!result&&slots.length>0&&<section className={`draft ${game==="era"?"pitch-draft":""}`}><div className="progress"><span>ROUND {Math.min(round+1,slots.length)} / {slots.length}</span><div>{slots.map((s,i)=><i className={i<round?"filled":i===round?"now":""} key={`${s}-${i}`}/>)}</div><b>{done?"SQUAD COMPLETE":game==="player"?`CHOOSE ${A[round]}`:"CHOOSE ANY PLAYER - PLACE THEM AFTER"}</b></div>{game==="era"&&!done?<div className="squad-builder"><div className="pitch-wrap"><span className="section-label">{formation?.name} · {ERAS.find(e=>e.id===selectedEra)?.label} · LIVE XI</span><Pitch slots={slots} picks={picks} current={-1} onSwap={swapPlayers} eraId={selectedEra} placementPlayer={options.find(p=>p.id===pendingPickId)} onPlace={placePending}/></div><div className="choice-panel"><div className="choice-heading"><div className="roster-draw compact"><span>LEAGUE <b>{drawPhase==="league"?"ROLLING...":drawLeague}</b></span><i>x</i><span>ERA <b>{drawPhase==="league"?"LOCKED NEXT":drawPhase==="era"?"ROLLING...":drawEra}</b></span><small>ANY POSITION / 5 PLAYERS</small></div><button className="reroll" disabled={rerollUsed||spinning} onClick={reroll}>{rerollUsed?"REROLL USED":"↻ ONE REROLL"}</button></div><div className={`cards ${drawPhase!=="players"?"drawing-roster":""}`}>{drawPhase==="players"?options.map(p=><Card key={p.id} p={p} eraId={selectedEra} selected={pendingPickId===p.id} spinning={spinning} onPick={()=>choosePlayer(p)}/>):Array.from({length:5},(_,i)=><div className="roster-slot" key={i}><span>{i+1}</span><b>{drawPhase==="league"?"ROLLING LEAGUE":drawPhase==="era"?"ROLLING ERA":"BUILDING ROSTER"}</b></div>)}</div><p className="draft-note">Elite, cult hero or honest pro? Every roll has a ceiling—and every era changes the fit.</p></div></div>:!done?<>{game==="perfect"&&<div className="five-draft-pitch"><Pitch slots={slots} picks={picks} current={-1} onSwap={swapPlayers} eraId={drawEraId} placementPlayer={options.find(p=>p.id===pendingPickId)} onPlace={placePending}/></div>}<div className="roster-draw standalone"><span>LEAGUE <b>{drawPhase==="league"?"ROLLING...":drawLeague}</b></span><i>x</i><span>ERA <b>{drawPhase==="league"?"LOCKED NEXT":drawPhase==="era"?"ROLLING...":drawEra}</b></span><small>{game==="perfect"?"5-PLAYER ROSTER - OUT-OF-POSITION PICKS ARE ALLOWED":"ATTRIBUTE MARKET"}</small></div><div className={`cards five-options ${drawPhase!=="players"&&game!=="player"?"drawing-roster":""}`}>{drawPhase==="players"||game==="player"?options.map(p=><Card key={p.id} p={p} attribute={game==="player"?A[round]:undefined} eraId={game==="perfect"?drawEraId:undefined} selected={pendingPickId===p.id} onPick={()=>game==="player"?pick(p):choosePlayer(p)}/>):Array.from({length:5},(_,i)=><div className="roster-slot" key={i}><span>{i+1}</span><b>{drawPhase==="league"?"ROLLING LEAGUE":drawPhase==="era"?"ROLLING ERA":"BUILDING ROSTER"}</b></div>)}</div></>:<div className="ready">{game==="era"?<div className="final-pitch"><Pitch slots={slots} picks={picks} current={-1} onSwap={swapPlayers}/></div>:<SquadSummary slots={slots} picks={picks} eraId={game==="perfect"?"20s":selectedEra}/>}<h2>{game==="perfect"?"CAN THE FIVE RULE THE TOUR?":game==="era"?"YOUR XI IS READY.":"THE PLAYER IS BUILT."}</h2>{game==="era"&&<p className="swap-hint">Drag players on the pitch to swap roles before simulating.</p>}<button className="primary" onClick={run}>SIMULATE THE SEASON <span>↗</span></button></div>}</section>}
